import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limiting the input size and copying data safely
        int maxLength = Math.min(name.length(), 10); // Limiting to 10 characters
        byte[] buffer = Arrays.copyOf(name.getBytes(), maxLength);

        System.out.println("Hello, " + new String(buffer));
    }
}

